const html = $input.item.json.data || $input.item.json;
const url = $('Set Variables').item.json.url;
const originalUrl = $('Set Variables').item.json.originalUrl;

try {
  // Look for the latest chapter link
  // Pattern captures: href, Chapter Number, and Title
  // Matches: <a href="URL" ...>Chapter 1000 – Title</a>
  const chapterPattern = /<a href="([^"]+)"[^>]*>\s*Chapter\s*(\d+)\s*[–-]\s*(.*?)<\/a>/g;
  const matches = [...html.matchAll(chapterPattern)];

  if (matches.length === 0) {
    throw new Error('No chapter numbers found in HTML');
  }

  // Get all chapter numbers and find the maximum
  let latestChapter = 0;
  let chapterName = '';
  let chapterUrl = '';

  for (const match of matches) {
    const num = parseInt(match[2]); // Capture group 2 is the number
    if (num > latestChapter) {
      latestChapter = num;
      chapterName = match[3].trim(); // Capture group 3 is the name
      chapterUrl = match[1]; // Capture group 1 is the URL
    }
  }

  if (isNaN(latestChapter) || latestChapter <= 0) {
    throw new Error('Invalid chapter number extracted: ' + latestChapter);
  }

  return {
    json: {
      latestChapter: latestChapter,
      chapterName: chapterName,
      chapterUrl: chapterUrl,
      url: url,
      originalUrl: originalUrl,
      uniqueName: $('Set Variables').item.json.uniqueName
    }
  };

} catch (error) {
  throw new Error('Failed to parse chapter number: ' + error.message + '\n\nHTML preview: ' + html.substring(0, 500));
}

const currentChapter = $('Extract Latest Chapter').item.json.latestChapter;
const chapterName = $('Extract Latest Chapter').item.json.chapterName;
const chapterUrl = $('Extract Latest Chapter').item.json.chapterUrl;
const dbResult = $('Get Stored Chapter').item.json;
const uniqueName = $('Extract Latest Chapter').item.json.uniqueName;
const url = $('Extract Latest Chapter').item.json.url;
const originalUrl = $('Extract Latest Chapter').item.json.originalUrl;

let storedChapter = null;
let isNewChapter = false;

// Check if database query was successful and returned data
if (dbResult && dbResult.data) {
  // Row exists in database - data is directly in dbResult.data
  try {
    storedChapter = parseInt(dbResult.data);
    // Only mark as new if current chapter is GREATER than stored
    isNewChapter = currentChapter > storedChapter;
    console.log(`Stored: ${storedChapter}, Current: ${currentChapter}, IsNew: ${isNewChapter}`);
  } catch (e) {
    console.log('Could not parse stored chapter, treating as new');
    isNewChapter = true;
  }
} else {
  // Row doesn't exist or query failed - assume current chapter is new
  console.log('No stored chapter found, treating current chapter as new');
  isNewChapter = true;
}

return {
  json: {
    currentChapter: currentChapter,
    chapterName: chapterName,
    chapterUrl: chapterUrl,
    storedChapter: storedChapter,
    isNewChapter: isNewChapter,
    uniqueName: uniqueName,
    url: url,
    originalUrl: originalUrl
  }
};

const error = $input.item.json.error || $input.item.json;
const nodeName = $runIndex === 0 ? 'Fetch Chapter Page' : 'Extract Latest Chapter';

let errorMessage = 'Unknown error';
let errorDetails = '';

if (typeof error === 'object') {
  errorMessage = error.message || JSON.stringify(error);
  if (error.description) {
    errorDetails = '\n\nDetails: ' + error.description;
  }
} else {
  errorMessage = String(error);
}

return {
  json: {
    message: '⚠️ *Error: Failed to Check Chapter*\n\n' +
             '*Novel:* Farming Life in Another World\n' +
             '*Error in:* ' + nodeName + '\n' +
             '*Message:* ' + errorMessage + errorDetails +
             '\n\n_Please check the workflow manually._'
  }
};
